2057	 * //   { label: 'tiger cat', score: 0.3634825646877289 },
2058	 * //   { label: 'lion, king of beasts, Panthera leo', score: 0.00045060308184474707 },
2059	 * //   { label: 'jaguar, panther, Panthera onca, Felis onca', score: 0.00035465499968267977 },
