2064	export class ImageClassificationPipeline extends (/** @type {new (options: ImagePipelineConstructorArgs) => ImageClassificationPipelineType} */ (Pipeline)) {
2065	
2066	    /**
2067	     * Create a new ImageClassificationPipeline.
