2495	        super(options);
2496	    }
2497	
2498	    /** @type {ObjectDetectionPipelineCallback} */
2499	    async _call(images, {
2500	        threshold = 0.9,
2501	        percentage = false,
2502	    } = {}) {
2503	
2504	        const isBatched = Array.isArray(images);
2505	
2506	        if (isBatched && images.length !== 1) {
2507	            throw Error("Object detection pipeline currently only supports a batch size of 1.");
2508	        }
2509	        const preparedImages = await prepareImages(images);
2510	
2511	        const imageSizes = percentage ? null : preparedImages.map(x => [x.height, x.width]);
2512	
2513	        const { pixel_values, pixel_mask } = await this.processor(preparedImages);
2514	        const output = await this.model({ pixel_values, pixel_mask });
2515	
2516	        // @ts-ignore
2517	        const processed = this.processor.image_processor.post_process_object_detection(output, threshold, imageSizes);
2518	
2519	        // Add labels
2520	        // @ts-expect-error TS2339
2521	        const id2label = this.model.config.id2label;
2522	
2523	        // Format output
2524	        /** @type {ObjectDetectionPipelineOutput[]} */
2525	        const result = processed.map(batch => (
2526	            batch.boxes.map((box, i) => ({
2527	                score: batch.scores[i],
2528	                label: id2label[batch.classes[i]],
2529	                box: get_bounding_box(box, !percentage),
2530	            }))
2531	        ))
2532	
2533	        return isBatched ? result : result[0];
2534	    }
